sealed class Shape
class Circle(val r: Double) : Shape()
class Square(val s: Double) : Shape()

fun area(shape: Shape) = when (shape) {
    is Circle -> 3.14 * shape.r * shape.r
    is Square -> shape.s * shape.s
}
println(area(Square(4.0)))

sealed class Animal {
    abstract val sound: String
}
class Cat : Animal() { override val sound = "Meow" }
class Dog : Animal() { override val sound = "Woof" }

fun makeSound(a: Animal) = println(a.sound)
makeSound(Cat())

sealed class Direction { }
class North : Direction()
class South : Direction()

fun label(d: Direction): String = when (d) {
    is North -> "N"
    is South -> "S"
}
